import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Gender = 'masculino' | 'feminino';

export interface AssessmentData {
  id: string;
  date: string;
  name: string;
  age: number;
  gender: Gender;
  weight: number; // kg
  height: number; // cm
  waist: number; // cm
  hip: number; // cm
  neck: number; // cm
}

export interface AssessmentResults {
  bmi: number;
  bmiCategory: string;
  bodyFatPercentage: number;
  leanMass: number;
  fatMass: number;
  bmr: number; // Basal Metabolic Rate
  waistToHipRatio: number;
}

export interface AssessmentEntry extends AssessmentData {
  results: AssessmentResults;
}

import { AssessmentData, AssessmentResults, Gender } from '../types';

export const calculateResults = (data: AssessmentData): AssessmentResults => {
  const heightInMeters = data.height / 100;
  const bmi = data.weight / (heightInMeters * heightInMeters);

  let bmiCategory = '';
  if (bmi < 18.5) bmiCategory = 'Abaixo do peso';
  else if (bmi < 25) bmiCategory = 'Peso normal';
  else if (bmi < 30) bmiCategory = 'Sobrepeso';
  else bmiCategory = 'Obesidade';

  // US Navy Body Fat Formula (Estimate)
  let bodyFatPercentage = 0;
  const log10 = Math.log10;

  if (data.gender === 'masculino') {
    bodyFatPercentage = 495 / (1.0324 - 0.19077 * log10(data.waist - data.neck) + 0.15456 * log10(data.height)) - 450;
  } else {
    bodyFatPercentage = 495 / (1.29579 - 0.35004 * log10(data.waist + data.hip - data.neck) + 0.22100 * log10(data.height)) - 450;
  }

  // Sanity check
  bodyFatPercentage = Math.max(2, Math.min(60, bodyFatPercentage));

  const fatMass = data.weight * (bodyFatPercentage / 100);
  const leanMass = data.weight - fatMass;

  // Mifflin-St Jeor Equation for BMR
  let bmr = (10 * data.weight) + (6.25 * data.height) - (5 * data.age);
  bmr = data.gender === 'masculino' ? bmr + 5 : bmr - 161;

  const waistToHipRatio = data.waist / data.hip;

  return {
    bmi,
    bmiCategory,
    bodyFatPercentage,
    leanMass,
    fatMass,
    bmr,
    waistToHipRatio
  };
};

export const formatDate = (dateString: string) => {
  return new Date(dateString).toLocaleDateString('pt-BR');
};

import { GoogleGenAI, Type } from "@google/genai";
import { AssessmentEntry } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAiInsights = async (assessment: AssessmentEntry) => {
  const prompt = `
    Analise esta avaliação física e forneça recomendações personalizadas:
    - Nome: ${assessment.name}
    - Idade: ${assessment.age} anos
    - Sexo: ${assessment.gender}
    - Peso: ${assessment.weight}kg, Altura: ${assessment.height}cm
    - IMC: ${assessment.results.bmi.toFixed(1)} (${assessment.results.bmiCategory})
    - Percentual de Gordura Estimado: ${assessment.results.bodyFatPercentage.toFixed(1)}%
    - Massa Magra: ${assessment.results.leanMass.toFixed(1)}kg
    - Taxa Metabólica Basal (TMB): ${assessment.results.bmr.toFixed(0)} kcal

    Por favor, retorne um objeto JSON com:
    1. "summary": Uma análise curta do estado atual.
    2. "risks": Possíveis riscos à saúde baseados nos dados.
    3. "suggestions": 3 dicas práticas de treino e nutrição.
    4. "motivation": Uma frase motivacional curta.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            risks: { type: Type.ARRAY, items: { type: Type.STRING } },
            suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            motivation: { type: Type.STRING }
          },
          required: ["summary", "risks", "suggestions", "motivation"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Erro ao gerar insights:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { AssessmentData, Gender } from '../types';

interface Props {
  onCalculate: (data: AssessmentData) => void;
}

const AssessmentForm: React.FC<Props> = ({ onCalculate }) => {
  const [formData, setFormData] = useState<Omit<AssessmentData, 'id' | 'date'>>({
    name: '',
    age: 25,
    gender: 'masculino',
    weight: 70,
    height: 175,
    waist: 80,
    hip: 95,
    neck: 38,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'name' || name === 'gender' ? value : Number(value)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCalculate({
      ...formData,
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
    });
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 space-y-6">
      <h2 className="text-xl font-semibold text-slate-800 border-b pb-3">Nova Avaliação</h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="space-y-1">
          <label className="text-sm font-medium text-slate-600">Nome Completo</label>
          <input
            required
            name="name"
            value={formData.name}
            onChange={handleChange}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
            placeholder="Ex: João Silva"
          />
        </div>

        <div className="grid grid-cols-2 gap-2">
          <div className="space-y-1">
            <label className="text-sm font-medium text-slate-600">Idade</label>
            <input
              type="number"
              name="age"
              value={formData.age}
              onChange={handleChange}
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-medium text-slate-600">Gênero</label>
            <select
              name="gender"
              value={formData.gender}
              onChange={handleChange}
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
            >
              <option value="masculino">Masculino</option>
              <option value="feminino">Feminino</option>
            </select>
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-sm font-medium text-slate-600">Peso (kg)</label>
          <input
            type="number"
            step="0.1"
            name="weight"
            value={formData.weight}
            onChange={handleChange}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
          />
        </div>

        <div className="space-y-1">
          <label className="text-sm font-medium text-slate-600">Altura (cm)</label>
          <input
            type="number"
            name="height"
            value={formData.height}
            onChange={handleChange}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
          />
        </div>

        <div className="space-y-1">
          <label className="text-sm font-medium text-slate-600">Cintura (cm)</label>
          <input
            type="number"
            step="0.1"
            name="waist"
            value={formData.waist}
            onChange={handleChange}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
          />
        </div>

        <div className="space-y-1">
          <label className="text-sm font-medium text-slate-600">Quadril (cm)</label>
          <input
            type="number"
            step="0.1"
            name="hip"
            value={formData.hip}
            onChange={handleChange}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
          />
        </div>

        <div className="space-y-1">
          <label className="text-sm font-medium text-slate-600">Pescoço (cm)</label>
          <input
            type="number"
            step="0.1"
            name="neck"
            value={formData.neck}
            onChange={handleChange}
            className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-emerald-500 outline-none transition"
          />
        </div>
      </div>

      <button
        type="submit"
        className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-semibold py-3 rounded-xl transition-all shadow-lg shadow-emerald-200 active:scale-95"
      >
        Calcular Resultados
      </button>
    </form>
  );
};

export default AssessmentForm;

import React from 'react';
import { AssessmentEntry } from '../types';
import { ResponsiveContainer, PieChart, Pie, Cell, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

interface Props {
  assessment: AssessmentEntry;
  history: AssessmentEntry[];
}

const ResultsDisplay: React.FC<Props> = ({ assessment, history }) => {
  const { results } = assessment;

  const pieData = [
    { name: 'Massa Magra', value: results.leanMass },
    { name: 'Massa Gorda', value: results.fatMass },
  ];

  const COLORS = ['#10b981', '#ef4444'];

  const historyData = history.slice(-5).map(h => ({
    date: new Date(h.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
    weight: h.weight,
    bf: h.results.bodyFatPercentage
  }));

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <ResultCard label="IMC" value={results.bmi.toFixed(1)} subtext={results.bmiCategory} color="indigo" />
        <ResultCard label="Gordura Corporal" value={`${results.bodyFatPercentage.toFixed(1)}%`} subtext="Método Marinha EUA" color="emerald" />
        <ResultCard label="TMB" value={`${results.bmr.toFixed(0)} kcal`} subtext="Metabolismo de Repouso" color="orange" />
        <ResultCard label="Relação C/Q" value={results.waistToHipRatio.toFixed(2)} subtext="Cintura / Quadril" color="rose" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold mb-4 text-slate-800">Composição Corporal</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex justify-center gap-6 text-sm">
            <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-emerald-500"></div> Massa Magra ({results.leanMass.toFixed(1)}kg)</div>
            <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-red-500"></div> Massa Gorda ({results.fatMass.toFixed(1)}kg)</div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold mb-4 text-slate-800">Evolução do Peso (Últimas 5)</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={historyData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="date" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="weight" fill="#6366f1" radius={[4, 4, 0, 0]} name="Peso (kg)" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

const ResultCard = ({ label, value, subtext, color }: { label: string, value: string, subtext: string, color: string }) => {
  const colors: Record<string, string> = {
    indigo: 'bg-indigo-50 text-indigo-700 border-indigo-100',
    emerald: 'bg-emerald-50 text-emerald-700 border-emerald-100',
    orange: 'bg-orange-50 text-orange-700 border-orange-100',
    rose: 'bg-rose-50 text-rose-700 border-rose-100',
  };

  return (
    <div className={`p-5 rounded-2xl border ${colors[color]} shadow-sm`}>
      <p className="text-xs font-bold uppercase tracking-wider opacity-70 mb-1">{label}</p>
      <p className="text-2xl font-bold">{value}</p>
      <p className="text-xs mt-1 opacity-80">{subtext}</p>
    </div>
  );
};

export default ResultsDisplay;

import React, { useState, useEffect } from 'react';
import { AssessmentEntry } from '../types';
import { getAiInsights } from '../services/geminiService';

interface Props {
  assessment: AssessmentEntry;
}

const AiInsightsPanel: React.FC<Props> = ({ assessment }) => {
  const [insights, setInsights] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchInsights = async () => {
      setLoading(true);
      setError(null);
      try {
        const data = await getAiInsights(assessment);
        setInsights(data);
      } catch (err) {
        setError("Não foi possível carregar os insights da IA no momento.");
      } finally {
        setLoading(false);
      }
    };

    fetchInsights();
  }, [assessment]);

  if (loading) {
    return (
      <div className="bg-gradient-to-br from-indigo-600 to-violet-700 p-8 rounded-2xl text-white shadow-xl animate-pulse">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-8 h-8 bg-white/20 rounded-full"></div>
          <div className="h-6 w-48 bg-white/20 rounded"></div>
        </div>
        <div className="space-y-3">
          <div className="h-4 w-full bg-white/20 rounded"></div>
          <div className="h-4 w-3/4 bg-white/20 rounded"></div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 p-6 rounded-2xl text-red-700 border border-red-100 text-sm">
        {error}
      </div>
    );
  }

  if (!insights) return null;

  return (
    <div className="bg-gradient-to-br from-indigo-600 to-violet-700 p-8 rounded-2xl text-white shadow-xl">
      <div className="flex items-center gap-3 mb-6">
        <div className="p-2 bg-white/20 rounded-lg">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
        </div>
        <h2 className="text-xl font-bold">Insights Inteligentes</h2>
      </div>

      <div className="space-y-6">
        <section>
          <p className="text-indigo-100 italic leading-relaxed">"{insights.summary}"</p>
        </section>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <section>
            <h3 className="text-sm font-bold uppercase tracking-wider mb-3 text-indigo-200">Recomendações</h3>
            <ul className="space-y-2">
              {insights.suggestions.map((s: string, i: number) => (
                <li key={i} className="flex gap-2 text-sm leading-snug">
                  <span className="text-emerald-400 font-bold">✓</span> {s}
                </li>
              ))}
            </ul>
          </section>

          <section>
            <h3 className="text-sm font-bold uppercase tracking-wider mb-3 text-indigo-200">Fatores de Atenção</h3>
            <ul className="space-y-2">
              {insights.risks.map((r: string, i: number) => (
                <li key={i} className="flex gap-2 text-sm leading-snug">
                  <span className="text-amber-400 font-bold">!</span> {r}
                </li>
              ))}
            </ul>
          </section>
        </div>

        <div className="pt-4 border-t border-white/10 text-center">
          <p className="text-lg font-medium tracking-tight">"{insights.motivation}"</p>
        </div>
      </div>
    </div>
  );
};

export default AiInsightsPanel;

import React, { useState, useEffect } from 'react';
import { AssessmentData, AssessmentEntry } from './types';
import { calculateResults } from './utils/calculations';
import AssessmentForm from './components/AssessmentForm';
import ResultsDisplay from './components/ResultsDisplay';
import AiInsightsPanel from './components/AiInsightsPanel';

const App: React.FC = () => {
  const [history, setHistory] = useState<AssessmentEntry[]>([]);
  const [currentAssessment, setCurrentAssessment] = useState<AssessmentEntry | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('fitcheck_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history");
      }
    }
  }, []);

  const handleCalculate = (data: AssessmentData) => {
    const results = calculateResults(data);
    const entry: AssessmentEntry = { ...data, results };

    setCurrentAssessment(entry);
    const newHistory = [...history, entry];
    setHistory(newHistory);
    localStorage.setItem('fitcheck_history', JSON.stringify(newHistory));

    // Smooth scroll to results
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const clearHistory = () => {
    if (confirm("Tem certeza que deseja apagar todo o histórico?")) {
      setHistory([]);
      localStorage.removeItem('fitcheck_history');
      setCurrentAssessment(null);
    }
  };

  return (
    <div className="min-h-screen flex flex-col pb-12">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-emerald-600 rounded-lg flex items-center justify-center text-white font-black italic">FP</div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">FitCheck <span className="text-emerald-600">Pro</span></h1>
          </div>
          <div className="hidden sm:block text-xs font-medium text-slate-400 uppercase tracking-widest">
            Gestão de Avaliação Física
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 mt-8 grid grid-cols-1 lg:grid-cols-3 gap-8 w-full">
        {/* Left Column: Form and Actions */}
        <div className="lg:col-span-1 space-y-6">
          <AssessmentForm onCalculate={handleCalculate} />

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-sm font-bold text-slate-400 uppercase mb-4 tracking-widest">Ações</h3>
            <div className="space-y-2">
              <button 
                onClick={() => setCurrentAssessment(null)}
                className="w-full text-left px-4 py-2 text-sm text-slate-600 hover:bg-slate-50 rounded-lg transition"
              >
                Nova Avaliação
              </button>
              <button 
                onClick={clearHistory}
                className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg transition"
              >
                Limpar Histórico
              </button>
            </div>
          </div>

          {/* Mini History View */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-sm font-bold text-slate-400 uppercase mb-4 tracking-widest">Últimas Avaliações</h3>
            {history.length === 0 ? (
              <p className="text-xs text-slate-400 italic">Nenhum registro encontrado.</p>
            ) : (
              <div className="space-y-3">
                {history.slice(-3).reverse().map((h) => (
                  <div 
                    key={h.id} 
                    onClick={() => setCurrentAssessment(h)}
                    className="p-3 rounded-xl bg-slate-50 hover:bg-emerald-50 border border-transparent hover:border-emerald-100 cursor-pointer transition"
                  >
                    <p className="text-sm font-semibold text-slate-700">{h.name}</p>
                    <div className="flex justify-between items-center mt-1">
                      <p className="text-[10px] text-slate-400 uppercase">{new Date(h.date).toLocaleDateString()}</p>
                      <p className="text-xs font-bold text-emerald-600">{h.weight}kg</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Right Column: Results and Insights */}
        <div className="lg:col-span-2 space-y-8">
          {currentAssessment ? (
            <>
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-bold text-slate-800">Resultados da Avaliação</h2>
                  <p className="text-slate-500 text-sm">Avaliação realizada em {new Date(currentAssessment.date).toLocaleDateString()} para {currentAssessment.name}</p>
                </div>
                <div className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-xs font-bold uppercase">Ativo</div>
              </div>

              <ResultsDisplay assessment={currentAssessment} history={history} />

              <AiInsightsPanel assessment={currentAssessment} />
            </>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-center p-12 bg-white rounded-3xl border-2 border-dashed border-slate-200">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-6">
                <svg className="w-10 h-10 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                </svg>
              </div>
              <h2 className="text-xl font-bold text-slate-800">Aguardando Avaliação</h2>
              <p className="text-slate-500 max-w-xs mt-2">Preencha os dados à esquerda ou selecione um registro no histórico para visualizar os resultados detalhados e insights de IA.</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

{
  "name": "FitCheck Pro - Avaliação Física Inteligente",
  "description": "Uma plataforma profissional para avaliação física, cálculos antropométricos e insights personalizados gerados por IA.",
  "requestFramePermissions": [
