export type Gender = 'masculino' | 'feminino';

export interface Skinfolds {
  pectoral: number;
  midaxillary: number;
  triceps: number;
  subscapular: number;
  abdominal: number;
  suprailiac: number;
  thigh: number;
}

export interface AssessmentData {
  id: string;
  date: string;
  name: string;
  age: number;
  gender: Gender;
  weight: number; // kg
  height: number; // cm
  waist: number; // cm
  hip: number; // cm
  neck: number; // cm
  photo?: string; // Base64 image
  skinfolds?: Skinfolds;
}

export interface AssessmentResults {
  bmi: number;
  bmiCategory: string;
  bodyFatPercentage: number;
  leanMass: number;
  fatMass: number;
  bmr: number; // Basal Metabolic Rate
  waistToHipRatio: number;
  methodUsed: 'Marinha' | 'Pollock 7';
  sumSkinfolds?: number;
}

export interface AssessmentEntry extends AssessmentData {
  results: AssessmentResults;
}

import { AssessmentData, AssessmentResults, Gender } from '../types';

export const calculateResults = (data: AssessmentData): AssessmentResults => {
  const heightInMeters = data.height / 100;
  const bmi = data.weight / (heightInMeters * heightInMeters);

  let bmiCategory = '';
  if (bmi < 18.5) bmiCategory = 'Abaixo do peso';
  else if (bmi < 25) bmiCategory = 'Peso normal';
  else if (bmi < 30) bmiCategory = 'Sobrepeso';
  else bmiCategory = 'Obesidade';

  let bodyFatPercentage = 0;
  let methodUsed: 'Marinha' | 'Pollock 7' = 'Marinha';
  let sumSkinfolds: number | undefined = undefined;

  // Check if skinfolds are provided
  if (data.skinfolds) {
    methodUsed = 'Pollock 7';
    const s = data.skinfolds;
    const sum = s.pectoral + s.midaxillary + s.triceps + s.subscapular + s.abdominal + s.suprailiac + s.thigh;
    sumSkinfolds = sum;

    let bodyDensity = 0;
    if (data.gender === 'masculino') {
      bodyDensity = 1.112 - (0.00043499 * sum) + (0.00000055 * Math.pow(sum, 2)) - (0.00028826 * data.age);
    } else {
      bodyDensity = 1.097 - (0.00046971 * sum) + (0.00000056 * Math.pow(sum, 2)) - (0.00012828 * data.age);
    }

    // Siri Equation
    bodyFatPercentage = (4.95 / bodyDensity - 4.50) * 100;
  } else {
    // US Navy Body Fat Formula
    const log10 = Math.log10;
    if (data.gender === 'masculino') {
      bodyFatPercentage = 495 / (1.0324 - 0.19077 * log10(data.waist - data.neck) + 0.15456 * log10(data.height)) - 450;
    } else {
      bodyFatPercentage = 495 / (1.29579 - 0.35004 * log10(data.waist + data.hip - data.neck) + 0.22100 * log10(data.height)) - 450;
    }
  }

  // Sanity check
  bodyFatPercentage = Math.max(2, Math.min(60, bodyFatPercentage));

  const fatMass = data.weight * (bodyFatPercentage / 100);
  const leanMass = data.weight - fatMass;

  // Mifflin-St Jeor Equation for BMR
  let bmr = (10 * data.weight) + (6.25 * data.height) - (5 * data.age);
  bmr = data.gender === 'masculino' ? bmr + 5 : bmr - 161;

  const waistToHipRatio = data.waist / data.hip;

  return {
    bmi,
    bmiCategory,
    bodyFatPercentage,
    leanMass,
    fatMass,
    bmr,
    waistToHipRatio,
    methodUsed,
    sumSkinfolds
  };
};

export const formatDate = (dateString: string) => {
  return new Date(dateString).toLocaleDateString('pt-BR');
};

import React, { useState, useRef } from 'react';
