  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCalculate({
      ...formData,
      photo,
      skinfolds: showSkinfolds ? skinfolds : undefined,
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
