          <SkinfoldInput label="Subescapular" name="subscapular" value={skinfolds.subscapular} onChange={handleSkinfoldChange} />
          <SkinfoldInput label="Abdominal" name="abdominal" value={skinfolds.abdominal} onChange={handleSkinfoldChange} />
          <SkinfoldInput label="Suprailíaca" name="suprailiac" value={skinfolds.suprailiac} onChange={handleSkinfoldChange} />
          <SkinfoldInput label="Coxa" name="thigh" value={skinfolds.thigh} onChange={handleSkinfoldChange} />
        </div>
      )}

      {/* Basic Measurements (still needed for ratios and fallback) */}
      <div className="grid grid-cols-3 gap-2">
        <div className="space-y-1">
          <label className="text-[10px] font-bold uppercase text-slate-400">Cintura</label>
          <input type="number" step="0.1" name="waist" value={formData.waist} onChange={handleChange} className="w-full px-2 py-1.5 text-sm rounded border border-slate-200 focus:ring-1 focus:ring-emerald-500" />
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-bold uppercase text-slate-400">Quadril</label>
          <input type="number" step="0.1" name="hip" value={formData.hip} onChange={handleChange} className="w-full px-2 py-1.5 text-sm rounded border border-slate-200 focus:ring-1 focus:ring-emerald-500" />
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-bold uppercase text-slate-400">Pescoço</label>
          <input type="number" step="0.1" name="neck" value={formData.neck} onChange={handleChange} className="w-full px-2 py-1.5 text-sm rounded border border-slate-200 focus:ring-1 focus:ring-emerald-500" />
        </div>
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium text-slate-600">Foto para Evolução</label>
        <div onClick={() => fileInputRef.current?.click()} className="relative group cursor-pointer border-2 border-dashed border-slate-200 hover:border-emerald-400 rounded-xl overflow-hidden transition-all bg-slate-50 h-32 flex flex-col items-center justify-center">
          {photo ? <img src={photo} alt="Preview" className="w-full h-full object-cover" /> : <div className="text-center p-2"><p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Selecionar Foto</p></div>}
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
      </div>

      <button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-semibold py-3 rounded-xl transition-all shadow-lg shadow-emerald-200 active:scale-95">Salvar e Calcular</button>
    </form>
  );
};

