            <span className="bg-slate-100 px-3 py-1 rounded-full text-xs font-bold text-slate-600">Σ Dobras: {results.sumSkinfolds?.toFixed(1)}mm</span>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            <SkinfoldBadge label="Peitoral" value={skinfolds.pectoral} />
            <SkinfoldBadge label="Axilar M." value={skinfolds.midaxillary} />
