          <h3 className="text-lg font-semibold mb-4 text-slate-800">Evolução Visual</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Anterior {previousAssessment ? `(${new Date(previousAssessment.date).toLocaleDateString()})` : ''}</p>
              <div className="aspect-[3/4] rounded-xl bg-slate-50 border border-slate-100 overflow-hidden flex items-center justify-center">
                {previousAssessment?.photo ? <img src={previousAssessment.photo} className="w-full h-full object-cover" alt="Anterior" /> : <div className="text-slate-300 flex flex-col items-center gap-2"><svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg></div>}
              </div>
              {previousAssessment && <div className="flex justify-between px-1"><span className="text-xs font-medium text-slate-500">{previousAssessment.weight}kg</span><span className="text-xs font-bold text-slate-700">BF: {previousAssessment.results.bodyFatPercentage.toFixed(1)}%</span></div>}
            </div>

            <div className="space-y-2">
              <p className="text-xs font-bold text-emerald-500 uppercase tracking-widest">Atual ({new Date(assessment.date).toLocaleDateString()})</p>
              <div className="aspect-[3/4] rounded-xl bg-emerald-50 border border-emerald-100 overflow-hidden flex items-center justify-center">
