          <h3 className="text-lg font-semibold mb-4 text-slate-800">Evolução do Peso</h3>
          <div className="h-64"><ResponsiveContainer width="100%" height="100%"><BarChart data={historyData}><CartesianGrid strokeDasharray="3 3" vertical={false} /><XAxis dataKey="date" /><YAxis /><Tooltip /><Bar dataKey="weight" fill="#6366f1" radius={[4, 4, 0, 0]} name="Peso (kg)" /></BarChart></ResponsiveContainer></div>
        </div>
      </div>
    </div>
  );
};

