const App: React.FC = () => {
  const [history, setHistory] = useState<AssessmentEntry[]>([]);
  const [currentAssessment, setCurrentAssessment] = useState<AssessmentEntry | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('fitcheck_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history");
      }
    }
  }, []);

  const handleCalculate = (data: AssessmentData) => {
    const results = calculateResults(data);
    const entry: AssessmentEntry = { ...data, results };

    setCurrentAssessment(entry);
    const newHistory = [...history, entry];
    setHistory(newHistory);
    localStorage.setItem('fitcheck_history', JSON.stringify(newHistory));

    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const clearHistory = () => {
    if (confirm("Tem certeza que deseja apagar todo o histórico?")) {
      setHistory([]);
      localStorage.removeItem('fitcheck_history');
      setCurrentAssessment(null);
    }
  };

  return (
    <div className="min-h-screen flex flex-col pb-12">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 shadow-sm">
        <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
          <Logo />
          <div className="hidden sm:block text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">
            Physical Assessment Pro
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 mt-8 grid grid-cols-1 lg:grid-cols-3 gap-8 w-full">
        {/* Left Column: Form and Actions */}
        <div className="lg:col-span-1 space-y-6">
          <AssessmentForm onCalculate={handleCalculate} />

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-sm font-bold text-slate-400 uppercase mb-4 tracking-widest">Ações</h3>
            <div className="space-y-2">
              <button 
                onClick={() => setCurrentAssessment(null)}
                className="w-full text-left px-4 py-2 text-sm text-slate-600 hover:bg-slate-50 rounded-lg transition"
              >
                Nova Avaliação
              </button>
              <button 
                onClick={clearHistory}
                className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg transition"
              >
                Limpar Histórico
              </button>
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-sm font-bold text-slate-400 uppercase mb-4 tracking-widest">Histórico Recente</h3>
            {history.length === 0 ? (
              <p className="text-xs text-slate-400 italic">Nenhum registro encontrado.</p>
            ) : (
              <div className="space-y-3">
                {history.slice(-3).reverse().map((h) => (
                  <div 
                    key={h.id} 
                    onClick={() => setCurrentAssessment(h)}
                    className="p-3 rounded-xl bg-slate-50 hover:bg-orange-50 border border-transparent hover:border-orange-100 cursor-pointer transition"
                  >
                    <p className="text-sm font-semibold text-slate-700">{h.name}</p>
                    <div className="flex justify-between items-center mt-1">
                      <p className="text-[10px] text-slate-400 uppercase">{new Date(h.date).toLocaleDateString()}</p>
                      <p className="text-xs font-bold text-orange-600">{h.weight}kg</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Right Column: Results and Insights */}
        <div className="lg:col-span-2 space-y-8">
          {currentAssessment ? (
            <>
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">Relatório de Performance</h2>
                  <p className="text-slate-500 text-sm">Cliente: <span className="font-bold text-slate-700">{currentAssessment.name}</span> • {new Date(currentAssessment.date).toLocaleDateString()}</p>
                </div>
                <div className="px-3 py-1 bg-orange-100 text-orange-700 rounded-full text-[10px] font-black uppercase tracking-widest">Ativo</div>
              </div>

              <ResultsDisplay assessment={currentAssessment} history={history} />

              <AiInsightsPanel assessment={currentAssessment} />
            </>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-center p-12 bg-white rounded-3xl border-2 border-dashed border-slate-200">
              <div className="w-20 h-20 bg-orange-50 rounded-full flex items-center justify-center mb-6">
                <svg className="w-10 h-10 text-orange-200" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                </svg>
