import React, { useState, useRef } from 'react';
import { AssessmentData, Gender, Skinfolds } from '../types';

interface Props {
  onCalculate: (data: AssessmentData) => void;
}

const AssessmentForm: React.FC<Props> = ({ onCalculate }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [photo, setPhoto] = useState<string | undefined>(undefined);
  const [showSkinfolds, setShowSkinfolds] = useState(false);

  const [formData, setFormData] = useState<Omit<AssessmentData, 'id' | 'date' | 'photo' | 'skinfolds'>>({
    name: '',
    age: 25,
    gender: 'masculino',
    weight: 70,
    height: 175,
    waist: 80,
    hip: 95,
    neck: 38,
  });

  const [skinfolds, setSkinfolds] = useState<Skinfolds>({
    pectoral: 0,
    midaxillary: 0,
    triceps: 0,
    subscapular: 0,
    abdominal: 0,
    suprailiac: 0,
    thigh: 0,
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'name' || name === 'gender' ? value : Number(value)
    }));
  };

  const handleSkinfoldChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setSkinfolds(prev => ({
      ...prev,
      [name]: Number(value)
    }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onCalculate({
      ...formData,
      photo,
      skinfolds: showSkinfolds ? skinfolds : undefined,
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
    });
    setPhoto(undefined);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 space-y-6">
      <h2 className="text-xl font-bold text-slate-800 border-b pb-3 uppercase tracking-tight">Nova Avaliação</h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="md:col-span-2 space-y-1">
          <label className="text-xs font-bold uppercase text-slate-400">Nome Completo</label>
          <input required name="name" value={formData.name} onChange={handleChange} className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition" placeholder="Ex: João Silva" />
        </div>

        <div className="space-y-1">
          <label className="text-xs font-bold uppercase text-slate-400">Idade</label>
          <input type="number" name="age" value={formData.age} onChange={handleChange} className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition" />
        </div>
        <div className="space-y-1">
          <label className="text-xs font-bold uppercase text-slate-400">Gênero</label>
          <select name="gender" value={formData.gender} onChange={handleChange} className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition">
            <option value="masculino">Masculino</option>
            <option value="feminino">Feminino</option>
          </select>
        </div>

        <div className="space-y-1">
          <label className="text-xs font-bold uppercase text-slate-400">Peso (kg)</label>
          <input type="number" step="0.1" name="weight" value={formData.weight} onChange={handleChange} className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition" />
        </div>
        <div className="space-y-1">
          <label className="text-xs font-bold uppercase text-slate-400">Altura (cm)</label>
          <input type="number" name="height" value={formData.height} onChange={handleChange} className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-orange-500 outline-none transition" />
        </div>
      </div>

      <div className="pt-2 border-t">
        <label className="flex items-center gap-2 cursor-pointer group">
          <input 
            type="checkbox" 
            className="w-4 h-4 rounded text-orange-600 focus:ring-orange-500" 
            checked={showSkinfolds}
            onChange={(e) => setShowSkinfolds(e.target.checked)}
          />
          <span className="text-sm font-bold text-slate-700 group-hover:text-orange-600 transition uppercase tracking-tight">Incluir Dobras (Pollock 7)</span>
        </label>
      </div>

      {showSkinfolds && (
        <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 grid grid-cols-2 gap-3 animate-in fade-in slide-in-from-top-2 duration-300">
          <SkinfoldInput label="Peitoral" name="pectoral" value={skinfolds.pectoral} onChange={handleSkinfoldChange} />
          <SkinfoldInput label="Axilar M." name="midaxillary" value={skinfolds.midaxillary} onChange={handleSkinfoldChange} />
          <SkinfoldInput label="Tríceps" name="triceps" value={skinfolds.triceps} onChange={handleSkinfoldChange} />
