export const exportHistoryToCsv = (history: AssessmentEntry[]) => {
  if (history.length === 0) return;

  // Cabeçalhos traduzidos e organizados
  const headers = [
    'Data',
    'Nome',
    'Idade',
    'Gênero',
    'Peso (kg)',
    'Altura (cm)',
    'Cintura (cm)',
    'Quadril (cm)',
    'Pescoço (cm)',
    'Peitoral (mm)',
    'Axilar Média (mm)',
    'Tríceps (mm)',
    'Subescapular (mm)',
    'Abdominal (mm)',
    'Suprailíaca (mm)',
    'Coxa (mm)',
    'IMC',
    'Status IMC',
    'Gordura corporal (%)',
    'Massa Magra (kg)',
    'Massa Gorda (kg)',
    'TMB (kcal)',
    'Método'
  ];

  // Formata o número para o padrão brasileiro do Excel (decimal com vírgula)
  const formatNum = (num: number | undefined) => {
    if (num === undefined || isNaN(num)) return '';
    return num.toFixed(2).replace('.', ',');
  };

  const rows = history.map(entry => {
    return [
      new Date(entry.date).toLocaleDateString('pt-BR'),
      entry.name,
      entry.age,
      entry.gender,
      formatNum(entry.weight),
      entry.height,
      formatNum(entry.waist),
      formatNum(entry.hip),
      formatNum(entry.neck),
      formatNum(entry.skinfolds?.pectoral),
      formatNum(entry.skinfolds?.midaxillary),
      formatNum(entry.skinfolds?.triceps),
      formatNum(entry.skinfolds?.subscapular),
      formatNum(entry.skinfolds?.abdominal),
      formatNum(entry.skinfolds?.suprailiac),
      formatNum(entry.skinfolds?.thigh),
      formatNum(entry.results.bmi),
      entry.results.bmiCategory,
      formatNum(entry.results.bodyFatPercentage),
      formatNum(entry.results.leanMass),
      formatNum(entry.results.fatMass),
      entry.results.bmr.toFixed(0),
      entry.results.methodUsed
    ].join(';'); // Excel BR usa ponto e vírgula
  });

  const csvContent = "\uFEFF" + [headers.join(';'), ...rows].join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');

  link.setAttribute('href', url);
  link.setAttribute('download', `AlexNego12_Fitness_Export_${new Date().getTime()}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

