                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                </svg>
              </div>
              <h2 className="text-xl font-bold text-slate-800 dark:text-white">Inicie sua Avaliação</h2>
              <p className="text-slate-500 dark:text-slate-400 max-w-xs mt-2 text-sm leading-relaxed">Insira os dados antropométricos à esquerda para gerar o diagnóstico de performance Alex Nego 12 Fitness.</p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

